def detect_project(cmdline: list[str], cwd: str | None) -> str:
    """Infiere a qué proyecto pertenece un proceso."""
    full = " ".join(cmdline) + " " + (cwd or "")
    for proj in KNOWN_PROJECTS:
        if proj.lower() in full.lower():
            return proj
    if CHANCE1_ROOT.lower() in full.lower():
        return "Hooks_IA/otro"
    return "Sistema"

def bar(pct: float, width: int = 30) -> str:
    filled = int(pct / 100 * width)
    return "[" + "█" * filled + "░" * (width - filled) + f"] {pct:5.1f}%"

